BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?name WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?verifier ?verifierName WHERE {
  ?verify rdf:type vocab:verify .
  ?verify vocab:Dependency_supplier ?req .
  ?verify vocab:Dependency_client ?verifier .
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName }
  OPTIONAL { ?verifier vocab:NamedElement_name ?verifierName }
}
LIMIT 50

